406→    private val gestureListener = OnTouchListener { _, event ->
407→        if (gestureDetector!!.onTouchEvent(event)) {
408→            return@OnTouchListener true
409→        }
410→        if (!gestureDetectorImpl.eventCanBeSentToWebView(event)) {
411→            return@OnTouchListener false
412→        }
413→        // Gesture listener is added before mCard is set
414→        processCardAction { cardWebView: WebView? ->
415→            if (cardWebView == null) return@processCardAction
416→            cardWebView.dispatchTouchEvent(event)
417→        }
418→        false
419→    }
