421→    // This is intentionally package-private as it removes the need for synthetic accessors
422→    @SuppressLint("CheckResult")
423→    fun processCardAction(cardConsumer: Consumer<WebView?>) {
424→        processCardFunction { cardWebView: WebView? ->
425→            cardConsumer.accept(cardWebView)
426→            true
427→        }
428→    }
