430→    @CheckResult
431→    private fun <T> processCardFunction(cardFunction: Function<WebView?, T>): T {
432→        val readLock = cardLock.readLock()
433→        return try {
434→            readLock.lock()
435→            cardFunction.apply(webView)
436→        } finally {
437→            readLock.unlock()
438→        }
439→    }

