 88→    abstract class Screen private constructor(val prefix: Char) {
 89→        abstract fun toPreferenceString(binding: Binding): String?
 90→        abstract fun toDisplayString(context: Context, binding: Binding): String
 91→        abstract fun screenEquals(otherScreen: Screen): Boolean
 92→
 93→        class Reviewer(val side: CardSide) : Screen('r') {
 94→            override fun toPreferenceString(binding: Binding): String? {
 95→                if (!binding.isValid) {
 96→                    return null
 97→                }
 98→                val s = StringBuilder()
 99→                s.append(prefix)
100→                s.append(binding.toString())
101→                // don't serialise problematic bindings
102→                if (s.isEmpty()) {
103→                    return null
104→                }
105→                when (side) {
106→                    CardSide.QUESTION -> s.append('0')
107→                    CardSide.ANSWER -> s.append('1')
108→                    CardSide.BOTH -> s.append('2')
109→                }
110→                return s.toString()
111→            }
112→
113→            override fun toDisplayString(context: Context, binding: Binding): String {
114→                val formatString = when (side) {
115→                    CardSide.QUESTION -> context.getString(R.string.display_binding_card_side_question)
116→                    CardSide.ANSWER -> context.getString(R.string.display_binding_card_side_answer)
117→                    else -> context.getString(R.string.display_binding_card_side_both) // intentionally no prefix
118→                }
119→                return String.format(formatString, binding.toDisplayString(context))
120→            }
121→
122→            override fun screenEquals(otherScreen: Screen): Boolean {
123→                val other: Reviewer = otherScreen as? Reviewer ?: return false
124→
125→                return side === CardSide.BOTH ||
126→                    other.side === CardSide.BOTH ||
127→                    side === other.side
128→            }
129→
130→            companion object {
131→                fun fromString(s: String): MappableBinding {
132→                    val binding = s.substring(0, s.length - 1)
133→                    val b = Binding.fromString(binding)
134→                    val side = when (s[s.length - 1]) {
135→                        '0' -> CardSide.QUESTION
136→                        '1' -> CardSide.ANSWER
137→                        else -> CardSide.BOTH
138→                    }
139→                    return MappableBinding(b, Reviewer(side))
140→                }
141→            }
142→        }
143→    }
