 31→/**
 32→ * Binding + additional contextual information
 33→ * Also defines equality over bindings.
 34→ * https://stackoverflow.com/questions/5453226/java-need-a-hash-map-where-one-supplies-a-function-to-do-the-hashing
 35→ */
 36→class MappableBinding(val binding: Binding, val screen: Screen) {
 37→    val isKey: Boolean get() = binding is KeyBinding
 38→
 39→    override fun equals(other: Any?): Boolean {
 40→        if (this === other) return true
 41→        if (other == null) return false
 42→
 43→        val otherBinding = (other as MappableBinding).binding
 44→        val bindingEquals = when {
 45→            binding is KeyCode && otherBinding is KeyCode -> binding.keycode == otherBinding.keycode && modifierEquals(otherBinding)
 46→            binding is UnicodeCharacter && otherBinding is UnicodeCharacter -> binding.unicodeCharacter == otherBinding.unicodeCharacter && modifierEquals(otherBinding)
 47→            binding is GestureInput && otherBinding is GestureInput -> binding.gesture == otherBinding.gesture
 48→            binding is AxisButtonBinding && otherBinding is AxisButtonBinding -> binding.axis == otherBinding.axis && binding.threshold == otherBinding.threshold
 49→            else -> false
 50→        }
 51→        if (!bindingEquals) {
 52→            return false
 53→        }
 54→
 55→        return screen.screenEquals(other.screen)
 56→    }
 57→
 58→    override fun hashCode(): Int {
 59→        // don't include the modifierKeys or mSide
 60→        val bindingHash = when (binding) {
 61→            is KeyCode -> binding.keycode
 62→            is UnicodeCharacter -> binding.unicodeCharacter
 63→            is GestureInput -> binding.gesture
 64→            is AxisButtonBinding -> hash(binding.axis.motionEventValue, binding.threshold.toInt())
 65→            else -> 0
 66→        }
 67→        return Objects.hash(bindingHash, screen.prefix)
 68→    }
 69→
 70→    private fun modifierEquals(otherBinding: KeyBinding): Boolean {
 71→        // equals allowing subclasses
 72→        val keys = otherBinding.modifierKeys
 73→        val thisKeys = (this.binding as KeyBinding).modifierKeys
 74→        if (thisKeys === keys) return true
 75→        return thisKeys.semiStructuralEquals(keys)
 76→
 77→        // allow subclasses to work - a subclass which overrides shiftMatches will return true on one of the tests
 78→    }
 79→
 80→    fun toDisplayString(context: Context): String {
 81→        return screen.toDisplayString(context, binding)
 82→    }
 83→
 84→    fun toPreferenceString(): String? {
 85→        return screen.toPreferenceString(binding)
 86→    }
 87→
 88→    abstract class Screen private constructor(val prefix: Char) {
 89→        abstract fun toPreferenceString(binding: Binding): String?
 90→        abstract fun toDisplayString(context: Context, binding: Binding): String
 91→        abstract fun screenEquals(otherScreen: Screen): Boolean
 92→
 93→        class Reviewer(val side: CardSide) : Screen('r') {
 94→            override fun toPreferenceString(binding: Binding): String? {
 95→                if (!binding.isValid) {
 96→                    return null
 97→                }
 98→                val s = StringBuilder()
 99→                s.append(prefix)
100→                s.append(binding.toString())
101→                // don't serialise problematic bindings
102→                if (s.isEmpty()) {
103→                    return null
104→                }
105→                when (side) {
106→                    CardSide.QUESTION -> s.append('0')
107→                    CardSide.ANSWER -> s.append('1')
108→                    CardSide.BOTH -> s.append('2')
109→                }
110→                return s.toString()
111→            }
112→
113→            override fun toDisplayString(context: Context, binding: Binding): String {
114→                val formatString = when (side) {
115→                    CardSide.QUESTION -> context.getString(R.string.display_binding_card_side_question)
116→                    CardSide.ANSWER -> context.getString(R.string.display_binding_card_side_answer)
117→                    else -> context.getString(R.string.display_binding_card_side_both) // intentionally no prefix
118→                }
119→                return String.format(formatString, binding.toDisplayString(context))
120→            }
121→
122→            override fun screenEquals(otherScreen: Screen): Boolean {
123→                val other: Reviewer = otherScreen as? Reviewer ?: return false
124→
125→                return side === CardSide.BOTH ||
126→                    other.side === CardSide.BOTH ||
127→                    side === other.side
128→            }
129→
130→            companion object {
131→                fun fromString(s: String): MappableBinding {
132→                    val binding = s.substring(0, s.length - 1)
133→                    val b = Binding.fromString(binding)
134→                    val side = when (s[s.length - 1]) {
135→                        '0' -> CardSide.QUESTION
136→                        '1' -> CardSide.ANSWER
137→                        else -> CardSide.BOTH
138→                    }
139→                    return MappableBinding(b, Reviewer(side))
140→                }
141→            }
142→        }
143→    }
144→
145→    /** the serialisation version */
146→    enum class Version {
147→        ONE
148→    }
149→
150→    companion object {
151→        const val PREF_SEPARATOR = '|'
152→
153→        @CheckResult
154→        fun fromGesture(gesture: Gesture, screen: (CardSide) -> Screen): MappableBinding = MappableBinding(GestureInput(gesture), screen(CardSide.BOTH))
155→
156→        @CheckResult
157→        fun List<MappableBinding>.toPreferenceString(): String = this.mapNotNull { it.toPreferenceString() }
158→            .joinToString(prefix = "1/", separator = PREF_SEPARATOR.toString())
159→
160→        @Suppress("UNUSED_PARAMETER")
161→        @CheckResult
162→        fun fromString(s: String, v: Version = Version.ONE): MappableBinding? {
163→            if (s.isEmpty()) {
164→                return null
165→            }
166→            return try {
167→                // the prefix of the serialized
168→                when (s[0]) {
169→                    'r' -> Screen.Reviewer.fromString(s.substring(1))
170→                    else -> null
171→                }
172→            } catch (e: Exception) {
173→                Timber.w(e, "failed to deserialize binding")
174→                null
175→            }
176→        }
177→
178→        @CheckResult
179→        fun fromPreferenceString(string: String?): MutableList<MappableBinding> {
180→            if (string.isNullOrEmpty()) return ArrayList()
181→            try {
182→                val version = string.takeWhile { x -> x != '/' }
183→                val remainder = string.substring(version.length + 1) // skip the /
184→                if (version != "1") {
185→                    Timber.w("cannot handle version '$version'")
186→                    return ArrayList()
187→                }
188→                return remainder.split(PREF_SEPARATOR).mapNotNull { fromString(it) }.toMutableList()
189→            } catch (e: Exception) {
190→                Timber.w(e, "Failed to deserialize preference")
191→                return ArrayList()
192→            }
193→        }
194→
195→        @CheckResult
196→        fun fromPreference(prefs: SharedPreferences, command: ViewerCommand): MutableList<MappableBinding> {
197→            val value = prefs.getString(command.preferenceKey, null) ?: return command.defaultValue.toMutableList()
198→            return fromPreferenceString(value)
199→        }
200→
201→        @CheckResult
202→        fun allMappings(prefs: SharedPreferences): MutableList<Pair<ViewerCommand, MutableList<MappableBinding>>> {
203→            return ViewerCommand.entries.map {
204→                Pair(it, fromPreference(prefs, it))
205→            }.toMutableList()
206→        }
207→    }
208→}
